/**
 * Quick Sort implementation
 */
function quickSort<T>(arr: T[], compare?: (a: T, b: T) => number): T[] {
  if (arr.length <= 1) return arr;

  const cmp = compare || ((a: T, b: T) => (a as any) > (b as any) ? 1 : -1);

  const pivot = arr[0];
  const left: T[] = [];
  const right: T[] = [];

  for (let i = 1; i < arr.length; i++) {
    if (cmp(arr[i], pivot) <= 0) {
      left.push(arr[i]);
    } else {
      right.push(arr[i]);
    }
  }

  return [...quickSort(left, cmp), pivot, ...quickSort(right, cmp)];
}

// In-place version (more memory efficient)
function quickSortInPlace<T>(
  arr: T[],
  left = 0,
  right = arr.length - 1,
  compare?: (a: T, b: T) => number
): void {
  if (left >= right) return;

  const cmp = compare || ((a: T, b: T) => (a as any) > (b as any) ? 1 : -1);

  const pivotIndex = partition(arr, left, right, cmp);
  quickSortInPlace(arr, left, pivotIndex - 1, cmp);
  quickSortInPlace(arr, pivotIndex + 1, right, cmp);
}

function partition<T>(
  arr: T[],
  left: number,
  right: number,
  compare: (a: T, b: T) => number
): number {
  const pivot = arr[right];
  let i = left - 1;

  for (let j = left; j < right; j++) {
    if (compare(arr[j], pivot) <= 0) {
      i++;
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
  }

  [arr[i + 1], arr[right]] = [arr[right], arr[i + 1]];
  return i + 1;
}

// Example usage
if (import.meta.main) {
  const numbers = [64, 34, 25, 12, 22, 11, 90];
  console.log("Original:", numbers);
  console.log("Sorted:", quickSort([...numbers]));

  const strings = ["banana", "apple", "cherry", "date"];
  console.log("Strings:", quickSort(strings));
}

export { quickSort, quickSortInPlace };

